## 🐛 Bug Report

Export Vietnamese garbled characters in CSV format

const ec = require('encoding');
const Excel = require('exceljs');
const { rows, cb, fileOptions, fileName, type } = opts;
const workbook = new Excel.Workbook();
const worksheet = workbook.addWorksheet('sheet');
this.addStyle(worksheet, rows);
cb(worksheet);
worksheet.addRows(rows);
ctx.set('Content-type', 'application/octet-stream;charset=gbk');
const fileBuffer = await workbook.csv.writeBuffer(fileOptions);
return ec.convert(fileBuffer, 'gbk', 'utf8');

